<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Kanban Board</title>
<style>
  :root {
    --bg: #f0f2f5;
    --col-bg: #e9ecf1;
    --card-bg: #ffffff;
    --text: #1f2733;
    --muted: #6b7686;
    --accent: #4f7cff;
    --danger: #e5484d;
    --radius: 12px;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background: var(--bg);
    color: var(--text);
    min-height: 100vh;
    padding: 32px 24px;
  }
  h1 {
    font-size: 1.5rem;
    font-weight: 700;
    margin-bottom: 20px;
    letter-spacing: -0.01em;
  }
  .toolbar {
    display: flex;
    gap: 10px;
    margin-bottom: 28px;
    max-width: 520px;
  }
  #new-card {
    flex: 1;
    padding: 10px 14px;
    font-size: 0.95rem;
    border: 1px solid #d3d9e2;
    border-radius: var(--radius);
    background: #fff;
    outline: none;
    transition: border-color .15s, box-shadow .15s;
  }
  #new-card:focus {
    border-color: var(--accent);
    box-shadow: 0 0 0 3px rgba(79, 124, 255, 0.15);
  }
  #add-card {
    padding: 10px 18px;
    font-size: 0.95rem;
    font-weight: 600;
    color: #fff;
    background: var(--accent);
    border: none;
    border-radius: var(--radius);
    cursor: pointer;
    transition: background .15s, transform .1s;
  }
  #add-card:hover { background: #3d68e8; }
  #add-card:active { transform: scale(0.97); }
  .board {
    display: grid;
    grid-template-columns: repeat(3, minmax(240px, 1fr));
    gap: 20px;
    align-items: start;
    max-width: 1100px;
  }
  .column {
    background: var(--col-bg);
    border-radius: calc(var(--radius) + 4px);
    padding: 14px;
    min-height: 220px;
    display: flex;
    flex-direction: column;
    transition: background .15s, outline-color .15s;
    outline: 2px dashed transparent;
    outline-offset: -2px;
  }
  .column.drag-over {
    background: #dde4ef;
    outline-color: var(--accent);
  }
  .column-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 4px 6px 12px;
  }
  .column-header h2 {
    font-size: 0.85rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.06em;
    color: var(--muted);
  }
  .count {
    font-size: 0.78rem;
    font-weight: 700;
    background: #d3d9e2;
    color: var(--text);
    border-radius: 999px;
    min-width: 24px;
    height: 24px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 0 8px;
  }
  .cards {
    display: flex;
    flex-direction: column;
    gap: 10px;
    min-height: 60px;
    flex: 1;
  }
  .card {
    background: var(--card-bg);
    border-radius: var(--radius);
    padding: 12px 14px;
    box-shadow: 0 1px 3px rgba(20, 30, 50, 0.10), 0 1px 2px rgba(20, 30, 50, 0.06);
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 10px;
    cursor: grab;
    transition: box-shadow .15s, transform .15s, opacity .15s;
  }
  .card:hover {
    box-shadow: 0 4px 12px rgba(20, 30, 50, 0.14);
    transform: translateY(-1px);
  }
  .card.dragging {
    opacity: 0.45;
    cursor: grabbing;
  }
  .card-title {
    font-size: 0.95rem;
    line-height: 1.4;
    word-break: break-word;
    padding-top: 1px;
  }
  .card-del {
    flex: none;
    width: 24px;
    height: 24px;
    border: none;
    border-radius: 6px;
    background: transparent;
    color: var(--muted);
    font-size: 1rem;
    line-height: 1;
    cursor: pointer;
    transition: background .15s, color .15s;
  }
  .card-del:hover {
    background: rgba(229, 72, 77, 0.12);
    color: var(--danger);
  }
  @media (max-width: 760px) {
    .board { grid-template-columns: 1fr; }
  }
</style>
</head>
<body>
  <h1>Kanban Board</h1>

  <div class="toolbar">
    <input id="new-card" type="text" placeholder="New card title…" autocomplete="off">
    <button id="add-card" type="button">Add card</button>
  </div>

  <div class="board">
    <section class="column" id="col-todo" data-col="todo">
      <div class="column-header">
        <h2>To Do</h2>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>
    <section class="column" id="col-doing" data-col="doing">
      <div class="column-header">
        <h2>Doing</h2>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>
    <section class="column" id="col-done" data-col="done">
      <div class="column-header">
        <h2>Done</h2>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>
  </div>

<script>
(function () {
  var STORAGE_KEY = "kanban-board-state-v1";
  var COLS = ["todo", "doing", "done"];
  var input = document.getElementById("new-card");
  var addBtn = document.getElementById("add-card");
  var nextId = 1;

  function columnEl(col) {
    return document.getElementById("col-" + col);
  }
  function cardsContainer(col) {
    return columnEl(col).querySelector(".cards");
  }

  function saveState() {
    var state = { cards: [] };
    COLS.forEach(function (col) {
      cardsContainer(col).querySelectorAll(".card").forEach(function (card) {
        state.cards.push({
          id: card.dataset.id,
          title: card.querySelector(".card-title").textContent,
          col: col
        });
      });
    });
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    } catch (e) { /* storage unavailable */ }
  }

  function updateCounts() {
    COLS.forEach(function (col) {
      var n = cardsContainer(col).querySelectorAll(".card").length;
      columnEl(col).querySelector(".count").textContent = n;
    });
  }

  function makeCard(id, title) {
    var card = document.createElement("div");
    card.className = "card";
    card.draggable = true;
    card.dataset.id = id;

    var titleEl = document.createElement("span");
    titleEl.className = "card-title";
    titleEl.textContent = title;

    var del = document.createElement("button");
    del.className = "card-del";
    del.type = "button";
    del.setAttribute("aria-label", "Delete card");
    del.textContent = "\u00D7";
    del.addEventListener("click", function () {
      card.remove();
      updateCounts();
      saveState();
    });

    card.appendChild(titleEl);
    card.appendChild(del);

    card.addEventListener("dragstart", function (e) {
      e.dataTransfer.setData("text/plain", id);
      e.dataTransfer.effectAllowed = "move";
      card.classList.add("dragging");
    });
    card.addEventListener("dragend", function () {
      card.classList.remove("dragging");
    });

    return card;
  }

  function addCard(title, col) {
    var id = "card-" + (nextId++);
    cardsContainer(col).appendChild(makeCard(id, title));
    updateCounts();
    saveState();
  }

  function handleAdd() {
    var title = input.value.trim();
    if (!title) return;
    addCard(title, "todo");
    input.value = "";
    input.focus();
  }

  addBtn.addEventListener("click", handleAdd);
  input.addEventListener("keydown", function (e) {
    if (e.key === "Enter") handleAdd();
  });

  COLS.forEach(function (col) {
    var colEl = columnEl(col);
    colEl.addEventListener("dragover", function (e) {
      e.preventDefault();
      e.dataTransfer.dropEffect = "move";
      colEl.classList.add("drag-over");
    });
    colEl.addEventListener("dragleave", function (e) {
      if (!colEl.contains(e.relatedTarget)) {
        colEl.classList.remove("drag-over");
      }
    });
    colEl.addEventListener("drop", function (e) {
      e.preventDefault();
      colEl.classList.remove("drag-over");
      var id = e.dataTransfer.getData("text/plain");
      if (!id) return;
      var card = document.querySelector('.card[data-id="' + id + '"]');
      if (!card) return;
      cardsContainer(col).appendChild(card);
      updateCounts();
      saveState();
    });
  });

  function loadState() {
    var raw = null;
    try {
      raw = localStorage.getItem(STORAGE_KEY);
    } catch (e) { /* storage unavailable */ }
    if (!raw) { updateCounts(); return; }
    var state;
    try {
      state = JSON.parse(raw);
    } catch (e) {
      updateCounts();
      return;
    }
    if (state && Array.isArray(state.cards)) {
      state.cards.forEach(function (c) {
        if (!c || typeof c.title !== "string") return;
        var col = COLS.indexOf(c.col) !== -1 ? c.col : "todo";
        var id = typeof c.id === "string" ? c.id : "card-" + (nextId++);
        var num = parseInt(String(id).replace("card-", ""), 10);
        if (!isNaN(num) && num >= nextId) nextId = num + 1;
        cardsContainer(col).appendChild(makeCard(id, c.title));
      });
    }
    updateCounts();
  }

  loadState();
})();
</script>
</body>
</html>
